function generatePrimeNumbers(n) {
  let primes = [];
  let num = 2;

  while (primes.length < n) {
    let isPrime = true;
    for (let i = 2; i < num; i++) {
      if (num % i === 0) {
        isPrime = false;
      }
    }
    if (isPrime) {
      primes.push(num);
    }
    num++;
  }
  return primes;
}

