fn binary_search(arr: &[i32], num: i32) -> i32 {
  // Get the length of the array
   let len = arr.len();

  // Start the left and right pointers
  let mut left_ptr = 0;
  let mut right_ptr = len;

  while left_ptr < right_ptr {
    let mid = (left_ptr + (right_ptr - left_ptr) / 2) as usize;

    if arr[mid] < num {
      left_ptr = mid + 1;
    } else if arr[mid] > num {
      right_ptr = mid;
    } else {
      return mid as i32;
    }
  }

  return -1;
}

