    Node root; 

    /* Returns true if binary tree with root as root is height-balanced */
    boolean isBalanced(Node root) 
    { 
        int lh;   /* for height of left subtree */

        int rh;  /* for height of right subtree */

        /* If tree is empty then return true */
        if (root == null) 
            return true; 

