def quick_sort(mylist): 
    if len(mylist) <= 1:
        return mylist
    pivot = mylist[len(mylist) // 2]
    left = [x for x in mylist if x < pivot]
    middle = [x for x in mylist if x == pivot]
    right = [x for x in mylist if x > pivot]
    return quick_sort(left) + middle + quick_sort(right)

