def job_scheduling(jobs):
    max_profits  = 0
    chosen_jobs = []
    jobs.sort(key=lambda x: x[1], reverse=True)
    while jobs: 
        job = jobs.pop(0)
        # Try to select the job
        valid = True
        for j in chosen_jobs:
            if j[0] < job[0]:
                valid = False
        if valid:
            max_profits += job[1]
            chosen_jobs.append(job)
    return max_profits

