def binary_search(array, target, low, high):
    if low > high:
        return -1

    mid = low + (high - low) // 2

    if array[mid] == target:
        return mid
    elif array[mid] > target:
        return binary_search(array, target, low, mid-1)
    else:
        return binary_search(array, target, mid+1, high)

