def Caesar_Cipher(text, shift):
    cipher_text=""
    for character in text: 
        if character.isalpha():
            ascii_val=ord(character)
            ascii_val+=shift 
            if character.isupper():
                if ascii_val>ord('Z'):
                    ascii_val-=26
                elif ascii_val < ord('A'):
                    ascii_val+=26
            else:
                if ascii_val>ord('z'):
                    ascii_val-=26
                elif ascii_val < ord('a'):
                    ascii_val+=26
            cipher_text+=chr(ascii_val)
        else:
            cipher_text+=character
    return cipher_text

