import java.util.HashMap;
import java.util.PriorityQueue;

// HuffmanNode class to represent each node of Huffman tree
class HuffmanNode
{
    int data;
    char c;
    HuffmanNode left;
    HuffmanNode right;
}

// The main Huffman tree class
public class HuffmanTree
{
    // This Huffman tree takes in a string and builds
    // a table containing the character to Huffman code mappings
    public HashMap<Character, String> buildTable(String s)
    {
        // Priority Queue to sort the Huffman trees
        PriorityQueue<HuffmanNode> q = new PriorityQueue<>
        ((o1, o2) -> o1.data - o2.data);

        // Populate the priority queue with Huffman node objects
        for (int i = 0; i < s.length(); i++)
        {
            HuffmanNode temp = new HuffmanNode();
            temp.c = s.charAt(i);
            temp.data = (int) temp.c;
            temp.left = null;
            temp.right = null;

            q.add(temp);
        }

        // Build the Huffman tree
        HuffmanNode root = null;
        while (q.size() > 1)
        {
            HuffmanNode x = q.peek();
            q.poll();

            HuffmanNode y = q.peek();
            q.poll();

            HuffmanNode sum = new HuffmanNode();
            sum.data = x.data + y.data;
            sum.c = '-';
            sum.left = x;
            sum.right = y;
            root = sum;
            q.add(sum);
        }

        // Store the Huffman codes in a table
        HashMap<Character, String> huffmanTable =
            new HashMap<>();
        printCode(root, "", huffmanTable);

        // Return the table
        return huffmanTable;
    }

    // Recursively traverse the Huffman tree to build
    // the table of Huffman codes
    public void printCode(HuffmanNode root, String s,
            HashMap<Character, String> huffmanTable)
    {
        if (root.left
                == null
            && root.right
                   == null
            && Character.isLetter(root.c))
        {
            huffmanTable.put(root.c, s);
            return;
        }

        printCode(root.left, s + "0", huffmanTable);
        printCode(root.right, s + "1", huffmanTable);
    }
}

