    public static int sum(int number){
        int result = 0;
        for (int i = 1; i <= number / 2; i++){
            if (number % i == 0 ){
                result += i;
            }
        }
        return result;
    }

    public static int[] getSumOfDivisors(int[] arr){
        int[] result = new int[arr.length];
        for (int i = 0; i < arr.length; i++){
            result[i] = sum(arr[i]);
        }
        return result;
    }

    public static void main(String[] args){
        int[] arr = {1, 8, 20};
        System.out.println(Arrays.toString(getSumOfDivisors(arr)));
    }
}

