		String str = "Hello World";
		StringBuilder sb = new StringBuilder(str);

		for (int i = 0; i < sb.length(); i++) {
			char c = sb.charAt(i); 

			int j = i + 1; 
			while (j < sb.length()) { 
				if (c == sb.charAt(j)) { 
					sb.setCharAt(j, Character.toUpperCase(c));
				}
				j++;
			} 
		} 

