     foreach (int x in inputArray) {
       if (!counted.ContainsKey(x)) {
         counted[x] = 1;
       } else {
         counted[x] += 1;
       }

       if (counted[x] > MAX_COUNT) {
         VALUE = x;
         MAX_COUNT = counted[x];
       }
     }

