def deepest_node(root):
    '''
    This function finds the deepest node in a binary tree.
    '''
    if not root:
        return None
    q = [root]
    while q:
        node = q.pop()
        if node.left:
            q.append(node.left)
        if node.right:
            q.append(node.right)

    return node

