def count_duplicates(A):
    # Create an empty dictionary 
    count = {}
    # Iterate over the array
    for elem in A:
        # Check if the element is already in the dictionary 
        if elem in count:
            # Increment the count of duplicates
            count[elem] += 1
        # If the element is not in the dictionary, add it with the count=0 
        else:
            count[elem] = 0
    # Calculate the number of elements that occur more than once
    num_duplicates = 0
    for elem, count in count.items():
        if count > 0:
            num_duplicates +=1
    # Return the number of duplicates 
    return num_duplicates

