def count_x(x, arr):
    l = 0 
    r = len(arr) - 1
    while l <= r: 
        mid = (l + r) // 2
        if arr[mid] < x: 
            l = mid + 1
        elif arr[mid] > x: 
            r = mid - 1
        else: 
            count = 1
            temp = mid - 1
            while arr[temp] == x and temp > 0: 
                count += 1
                temp -= 1
            temp = mid + 1
            while arr[temp] == x and temp < len(arr): 
                count += 1
                temp += 1
            return count
    return 0

