def edit_distance(word1, word2):
  m = len(word1) + 1
  n = len(word2) + 1

  edit_matrix = [[0 for i in range(n)] for j in range(m)] 

  for i in range(m): 
    edit_matrix[i][0] = i  
  for j in range(n): 
    edit_matrix[0][j] = j  

  for i in range(1, m):
    for j in range(1, n): 
      if word1[i-1] == word2[j-1]: 
        cost = 0
      else:
        cost = 1 
      edit_matrix[i][j] = min(edit_matrix[i-1][j] + 1, edit_matrix[i][j-1] + 1, edit_matrix[i-1][j-1] + cost)

  return edit_matrix[m-1][n-1]

