// A JavaScript program to find the maximum sub-array using the Divide and Conquer algorithm
function maxSubArray(arr, start, end) {
 // Base case
 if (start === end) {
  return arr[start];
 }

 // Find mid-point of the array
 let mid = Math.floor((start + end) / 2);

 // Recursively find max sub-arrays
 let left = maxSubArray(arr, start, mid);
 let right = maxSubArray(arr, mid + 1, end);

 // Find the maximum cross-subarray
 let cross = maxCrossSubArray(arr, start, mid, end);

 // Return the maximum of all three
 return Math.max(left, right, cross);
}

// A helper function to find the maximum cross-subarray
function maxCrossSubArray(arr, start, mid, end) {
 let sum = 0;
 let left_sum = Number.MIN_SAFE_INTEGER;
 let right_sum = Number.MIN_SAFE_INTEGER;

 // Calculate the left side of the cross array
 for (let i = mid; i >= start; i--) {
  sum += arr[i];

  if (sum > left_sum) {
   left_sum = sum;
  }
 }

 // Reset the sum
 sum = 0;

 // Calculate the right side of the cross array
 for (let j = mid + 1; j <= end; j++) {
  sum += arr[j];

  if (sum > right_sum) {
   right_sum = sum;
  }
 }

 // Return maximum of left and right sum
 return left_sum + right_sum;
}

// Driver code
let arr = [-2, 1, -3, 4, -1, 2, 1, -5, 4];
let n = arr.length;
let max = maxSubArray(arr, 0, n - 1);
console.log(max); // Outputs 6

