// Function to separate first half and second half
void separateArray(int arr[], int N, int mid)
{
    int i, j;

    // Separating the array elements
    for (i = 0, j = N - 1; i < j;)
    {
        while (i < mid && arr[i] < 0)
            i++;
        while (j >= mid && arr[j] > 0)
            j--;

        if (i < j)
        {
            int temp = arr[i];
            arr[i] = arr[j];
            arr[j] = temp;
        }
    }
}

