{
    int arr[] = {3, 5, 7, 8, 9, 10, 12};
    int N = sizeof(arr) / sizeof(arr[0]);

    int mid = 8;

    separateArray(arr, N, mid);

    // Print elements of array
    for (int i = 0; i < N; i++)
        printf("%d, ", arr[i]);

    return 0;
}

