function longestCommonPrefix(list) {
 // Initialize longest common prefix
 let lcp = '';

 // Sort the list in order of increasing length
 list.sort((a, b) => a.length - b.length);

 // Find the shortest string in the list
 const shortestString = list[0];

 // Iterate over each character in the shortest string
 for(let i = 0; i < shortestString.length; i++) {
 let char = shortestString[i];
 // Iterate over each string in the list
 for(let j = 1; j < list.length; j++){
 // Compare the character with the corresponding character in the other strings
 if (char != list[j][i]) {
 // If the characters don't match, return the longest common prefix
 return lcp;
 }
 }
 // If the characters match, add the character to the longest common prefix
 lcp += char;
 }
 // If all characters in the shortest string match with the corresponding characters in the other strings
 // return the longest common prefix
 return lcp;
}

let list = ["abcabcbb", "abcba", "abccccd", "abcd"];
let res = longestCommonPrefix(list);
console.log(`The longest common prefix is: ${res}.`);

