vector < vector <int > > generate_pascals_triangle(int numRows) 
{ 
	vector < vector <int> > ans; 
	vector <int> curr_row; 

	if (numRows == 0) { 
		return ans; 
	} 

	curr_row.push_back(1); 
	ans.push_back(curr_row); 

	for (int i = 1; i < numRows; i++) 
	{ 
		curr_row.clear(); 
		curr_row.push_back(1); 

		for (int j = 1; j <= (i+1) / 2; j++) 
		{ 
			(ans[i-1][j-1] + ans[i-1][j] > INT_MAX) ? 
					curr_row.push_back(-1) : 
					curr_row.push_back(ans[i-1][j-1] + ans[i-1][j]); 
		} 

		if (i % 2 == 1) 
			curr_row.push_back(ans[i-1][(i / 2)] + ans[i-1][(i / 2)]); 
		else
			curr_row.push_back(2 * ans[i-1][(i / 2) - 1]); 

		for (int j = (i+1) / 2 - 1; j >= 0; j--) 
			curr_row.push_back(curr_row[j]); 

		ans.push_back(curr_row); 
	} 
	return ans; 
}

