import numpy as np 

class RL_Agent(): 
    def __init__(self, game): 
        self.game = game 
        self.states = game.states 
        self.moves = game.moves 

    def optimalPolicy(self): 
        q_table = dict() 
        rewards = dict()
        discount_rate = 0.95 

        # Initialize the q_table and rewards 
        for state in self.states:
            q_table[state] = {m:0 for m in self.moves} 
            rewards[state] = 0 

        for iteration in range(1000):
            s = np.random.choice(self.states) 
            is_over, reward = self.game.play(s, q_table[s]) 
            # we get the reward from the game 
            rewards[s] = reward 

            # check if the game ended 
            if is_over:
                for move in self.moves: 
                    q_table[s][move] = reward 
            else: 
                # if the game did not end we get the q_value by 
                # taking the maximum among all the possible actions
                q_val = reward + discount_rate * max([q_table[s1][m] 
                                for s1, m in self.game.next_states(s)]) 

                # update the q_table 
                for move in self.moves: 
                    q_table[s][move] = q_val 

        # choose the best policy from q_table
        policy = dict() 
        for s in self.states: 
            policy[s] = max(q_table[s], key=q_table[s].get) 

        return policy

