package main

import (
  "fmt"
  "net/http"
  "crypto/md5"
)

// A map to store shortcut and its corresponding URL
var ShortcutsMap map[string]string

func shortenURL(w http.ResponseWriter, r *http.Request) {
  // get the URL to be shortened
  url := r.URL.Query().Get("url")

  // generate a unique key
  key := generateUniqueKey(url)

  // add the URL and key to our map
  ShortcutsMap[key] = url

  // Return the key as the shortened URL
  fmt.Fprintln(w, key)

}

func retrieveURL(w http.ResponseWriter, r *http.Request) {
  // get the URL key
  urlKey := r.URL.Path[1:]

  // get the URL from the map if present
  if (ShortcutsMap[urlKey] != "") {
    http.Redirect(w, r, ShortcutsMap[urlKey], http.StatusFound)
  } else {
    http.NotFound(w, r)
  }

}

func generateUniqueKey(url string) string {
  // Generate the MD5 hash of the URL
  hash := md5.Sum([]byte(url))

  // Convert the hash to base58
  return base58.Encode(hash[:])

}

func main() {
  ShortcutsMap = make(map[string]string)

  http.HandleFunc("/shorten", shortenURL)
  http.HandleFunc("/", retrieveURL)
  http.ListenAndServe(":8080", nil)
}

