public class SpiralMatrix {

  public static void printSpiralMatrix(int[][] matrix) {
    int length = matrix.length * matrix[0].length;

    int x = 0;
    int y = 0;
    int rowEnd = matrix.length - 1;
    int columnEnd = matrix[0].length - 1;

    while (length > 0) {
      // Printing the first row
      for (int i = x; i <= columnEnd; i++) {
        System.out.print(matrix[x][i] + " ");
        length--;
      }
      x++;

      // Printing the last column
      for (int i = x; i <= rowEnd; i++) {
        System.out.print(matrix[i][columnEnd] + " ");
        length--;
      }
      columnEnd--;

      // Printing the last row
      if (length > 0) {
        for (int i = columnEnd; i >= y; i--) {
          System.out.print(matrix[rowEnd][i] + " ");
          length--;
        }
        rowEnd--;
      }

      // Printing the first column
      if (length > 0) {
        for (int i = rowEnd; i >= x; i--) {
          System.out.print(matrix[i][y] + " ");
          length--;
        }
        y++;
      }
   }
  }
}

