def find_longest_subsequence(numbers):
    longest_subsequence = []
    temp_subsequence = []

    # iterate through the sequence of numbers
    for num in numbers:
        # if the number is greater than the previous one
        if (len(temp_subsequence) == 0 or num > temp_subsequence[-1]):
            # add it to the current temp subsequence
            temp_subsequence.append(num)
        # otherwise, if the number is less than the previous one
        else:
            # update the longest subsequence if current temp subsequence is 
            # longer than the longest subsequence
            if (len(temp_subsequence) > len(longest_subsequence)):
                longest_subsequence = temp_subsequence
            temp_subsequence = [num]

    # check if current temp subsequence is longer than the longest one
    if (len(temp_subsequence) > len(longest_subsequence)):
        longest_subsequence = temp_subsequence 

    return longest_subsequence

