def find_most_frequent_number(arr):
    """This function finds the most frequent number in a two-dimensional array."""
    # Create a dictionary mapping from elements to their frequencies
    frequency_dict = {}
    # Iterate over the array
    for row in arr:
        for num in row:
            if num in frequency_dict:
                # Increase the frequency if the element is seen before
                frequency_dict[num] += 1 
            else:
                # Set the frequency to 1 if the element is not seen before
                frequency_dict[num] = 1

    # Find the most frequent element 
    most_frequent_number = None
    highest_frequency = 0
    for num, frequency in frequency_dict.items():
        if frequency > highest_frequency:
            highest_frequency = frequency
            most_frequent_number = num

    # Return the most frequent number
    return most_frequent_number

