public boolean validateCreditCard(String number)
{
  int digits = number.length();
  int odd_sum = 0;
  int even_sum = 0;
  boolean isOdd = false;

  for (int count = digits - 1; count >= 0; count--) {
    int digit = Integer.parseInt(number.substring(count, count + 1));

    if (isOdd) {
      odd_sum += digit;
    } else {
      even_sum += digit/5 + (2*digit) % 10;
    }
    isOdd = !isOdd;
  }
  return ((odd_sum + even_sum) % 10 == 0);
}

