 const addBook = (book) => {
 setBooks([ ...books, book ]);
 }

 const editBook = (index, newBook) => {
 const updatedBooks = [ ...books ];
 updatedBooks[index] = newBook;
 setBooks(updatedBooks);
 }

 const deleteBook = (index) => {
 const updatedBooks = books.filter((book, i) => i !== index);
 setBooks(updatedBooks);
 }

 return (
 <div>
 <h1>My Reading List</h1>
 <ul>
 {books.map((book, i) => (
 <li key={i}>{book}</li>
 ))}
