 <input type="text" ref={input}/>
 <button onClick={() => addBook(input.current.value)}>Add Book</button>
 <button onClick={() => editBook(selectedIndex, input.current.value)}>Edit Book</button>
 <button onClick={() => deleteBook(selectedIndex)}>Delete Book</button>
 </div>
 )
}

