#include <stdio.h>
#include <stdlib.h>

// Function to find the two missing numbers in
// an array of size n and given that the elements
// of the array are from 1 to n+2
void get2MissingNumbers(int arr[], int n)
{
    // Initialize result
    int xor1;
    int x = 0;
    int y = 0;

    // Get the xor of all the array elements
    xor1 = arr[0];
    for (int i = 1; i <= n; i++)
        xor1 ^= i;

    // Get the rightmost set bit in set_bit_no
    int set_bit_no = xor1 & ~(xor1-1);

    // Now divide elements in two sets by comparing 
    // rightmost set bit of xor1 with bit at same
    // position in each element of the array
    for (int i=0; i<n; i++)
    {
        if (arr[i] & set_bit_no)
            x = x ^ arr[i];
        else
            y = y ^ arr[i];
    }

    // Now the missing numbers are x and y
    for (int i=1; i<=n+2; i++)
    {
        if (xor1 ^ i == x)
            printf("%d ", i);
        if (xor1 ^ i == y)
            printf("%d ", i);
    }
}

// Driver program to test above function
int main()
{
    int arr[] = {3, 1, 6, 5, 4, 7};
    int n = 7;
    get2MissingNumbers(arr, n);
    return 0;
}

