    job.setStatus("pending");
    job.setData(new ArrayList<String>());

    // Store job in map
    UUID id = UUID.randomUUID();
    jobs.put(id, job);

    // Set ID
    job.setId(id);

    return job;
  }

  // Endpoint to get the status of a scraping job
  @GetMapping("/jobs/{id}/")
  public ScraperJob getJobStatus (@PathVariable("id") UUID id) {
    return jobs.get(id);
  }

  // Endpoint to cancel a scraping job
  @DeleteMapping("/jobs/{id}/")
  public String cancelJob (@PathVariable("id") UUID id) {
    jobs.remove(id);
    return "Job cancelled";
  }

