delimiters: [',', '.'] ### Output: #include <vector>
#include <string>
#include <sstream>

std::vector<std::string> tokenizeString(const std::string &str, const std::vector<char> &delimiters) {
 std::vector<std::string> output;

 std::stringstream ss(str);
 std::string token;
 while (getline(ss, token, *delimiters.begin())) {
  if (token.size() > 0) {
   output.push_back(token);
  }

  for (auto itr = std::next(delimiters.begin(), 1); itr != delimiters.end(); ++itr) {
   for (auto &subtoken : output) {
    token.clear();
    std::stringstream single_ss(subtoken);
    while (getline(single_ss, token, *itr)) {
     if (token.size() > 0) {
      subtoken = token;
     }
    }
   }
  }
 }

 return output;
}

