def find_most_frequent_words(sentence):
    words = sentence.split()
    word_occurrences = {}

    for word in words:
        if word in word_occurrences:
            word_occurrences[word] += 1
        else:
            word_occurrences[word] = 1

    most_frequent_words = []
    highest_occurrences = 0
    for word, occurrences in word_occurrences.items():
        if occurrences > highest_occurrences:
            most_frequent_words = [word]
            highest_occurrences = occurrences
        elif occurrences == highest_occurrences:
            most_frequent_words.append(word)

    return most_frequent_words

