void merge_sort(int arr[], int len) {
    if (len < 2) return;
    int mid = len / 2;
    int left[mid], right[len - mid];
    for (int i = 0; i < mid; i++) {
        left[i] = arr[i];
    }
    for (int i = mid; i < len; i++){
        right[i - mid] = arr[i];
    }
    merge_sort(left, mid);
    merge_sort(right, len - mid);
    merge(arr, left, right, mid, len - mid);
}

void merge(int arr[], int left[], int right[], int left_length, int right_length) {
    int i = 0, j = 0, k = 0;
    while (i < left_length && j < right_length) {
        if (left[i] < right[j]) {
            arr[k] = left[i];
            i++;
        } else {
            arr[k] = right[j];
            j++;
        }
        k++;
    }
    while (i < left_length) {
        arr[k] = left[i];
        k++;
        i++;
    }
    while (j < right_length) {
        arr[k] = right[j];
        k++;
        j++;
    }
}

