#include <iostream>
#include <cmath>

bool isArmstrongNumber(int number)
{
    int originalNumber, remainder, n = 0, result = 0;
    originalNumber = number;

    while (originalNumber != 0)
    {
        originalNumber /= 10;
        ++n;
    }

    originalNumber = number;
    while (originalNumber != 0)
    {
        remainder = originalNumber % 10;
        result += pow(remainder, n);
        originalNumber /= 10;
    }

    if (result == number)
        return true;
    else
        return false;
}

int main()
{
    int number = 153;
    bool isArmstrongNumberCheck = isArmstrongNumber(number);
    if(isArmstrongNumberCheck)
        std::cout << number << " is an Armstrong number.";
    else
       std::cout << number << " is not an Armstrong number.";
    return 0;
}

