import React, {useState, useEffect} from 'react';
import {
 StyleSheet,
 View,
 Text,
 TouchableOpacity,
 AppState,
} from 'react-native';
import MapView, {PROVIDER_GOOGLE} from 'react-native-maps';
import * as Location from 'expo-location';
import * as Permissions from 'expo-permissions';
import {Platform} from 'expo-core';

import db from './database';

const styles = StyleSheet.create({
 container: {
 flex: 1,
 alignItems: 'center',
 justifyContent: 'center',
 },
});

function RunningActivity() {
 const [locationData, setLocationData] = useState({
 route: [],
 distance: 0,
 timeElapsed: 0,
 });

useEffect(() => {
 getLocationPermissions();
 AppState.addEventListener('change', onBackgroundChange);
 return () => {
 AppState.removeEventListener('change', onBackgroundChange);
 };
 }, []);

const getLocationPermissions = async () => {
 // Prompt user for GPS permission
 const {status: existingStatus} = await Permissions.getAsync(
 Permissions.LOCATION
 );
 let finalStatus = existingStatus;
 if (existingStatus !== 'granted') {
 // iOS only: prompt the user if they haven't previously granted permission
 const {status} = await Permissions.askAsync(Permissions.LOCATION);
 finalStatus = status;
 }
 if (finalStatus === 'granted') {
 // iOS only: start the location service immediately
 if (Platform.OS === 'ios') {
 Location.startLocationUpdatesAsync('my-location', {
 accuracy: Location.Accuracy.BestForNavigation,
 });
 } else {
 // Android only:
 // trigger a location update, it will only
 // happen if the user is actually using the application (no background use)
 await Location.requestPermissionsAsync();
 }
 Location.watchPositionAsync(
 {
 accuracy: Location.Accuracy.BestForNavigation,
 },
 locationChanged
 );
 }
};

const locationChanged = location => {
 // update the state's location data with the location details
 const {coords, timestamp} = location;
 const {latitude, longitude} = coords;

 // save data points in route array
 const newPoint = { latitude, longitude };
 const route = [...locationData.route, newPoint];

 setLocationData({
 route,
 distance: calculateDistance(route),
 timeElapsed: timestamp - locationData.startTime,
 });
 saveDataInDatabase(locationData);
};

const calculateDistance = route => {
 let totalDistance = 0;
 for (let i = 0; i < route.length - 1; i++) {
 const start = route[i];
 const end = route[i + 1];
 totalDistance += getDistanceBetweenTwoPoints(start, end);
 }
 return totalDistance;
};

const getDistanceBetweenTwoPoints = (start, end) => {
 return haversine(start, end);
};

// Haversine formula to get distance between two GPS points
const haversine = (start, end) => {
 const R = 6371; // Radius of the earth in km
 const dLat = degreesToRadians(end.latitude - start.latitude);
 const dLon = degreesToRadians(end.longitude - start.longitude);
 const a =
 Math.sin(dLat / 2) * Math.sin(dLat / 2) +
 Math.cos(degreesToRadians(start.latitude)) *
 Math.cos(degreesToRadians(end.latitude)) *
 Math.sin(dLon / 2) * Math.sin(dLon / 2);
 const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
 const distance = R * c; // Distance in km
 return distance;
};

const degreesToRadians = degrees => {
 const radians = (degrees * Math.PI) / 180;
 return radians;
};

const saveDataInDatabase = locationData => {
 db.ref('run_data').push(locationData);
};

const onBackgroundChange = async state => {
 if (state === 'background') {
 // Stop sending location in the background
 Location.stopLocationUpdatesAsync('my-location');
 saveDataInDatabase(locationData);
 }
};

return (
 <View style={styles.container}>
 {locationData.route.length > 0 ? (
 <MapView
 provider={PROVIDER_GOOGLE}
 style={{width: '100%', height: '50%'}}
 region={{...locationData.route[locationData.route.length - 1] }}
 >
 {locationData.route.map((location, index) => (
 <MapView.Marker
 key={index}
 coordinate={{...location}}
 />
 ))}
 </MapView>
 ) : null}
 </View>
 );
}

export default RunningActivity;

