def create_language_model(text, keyword):
  ngrams = nltk.ngrams(text.split(), 4)
  model = defaultdict(lambda: defaultdict(lambda: 0))

  for w1, w2, w3, w4 in ngrams:
    if w1 == keyword:
      model[(w1, w2, w3)][w4] += 1

  for w1_w2_w3 in model:
    total_count = float(sum(model[w1_w2_w3].values()))
    for w4 in model[w1_w2_w3]:
      model[w1_w2_w3][w4] /= total_count

  return model

