def find_longest_subarray_length(arr):
    s = 0
    e = 0
    max_length = 0
    while e < len(arr):
        if arr[e] == 1:
            e += 1
        else:
            num_ones = e - s
            num_zeros = 1
            while e < len(arr) and arr[e] == 0:
                num_zeros += 1
                e += 1
            if num_ones == num_zeros:
                max_length = max(max_length, (num_ones + num_zeros))
            s = e
    return max_length

