import java.util.Arrays;

public class LIS { 

    static int findLIS(int[] arr) 
    { 
        int n = arr.length; 

        // allocate memory 
        int[] lis = new int[n]; 

        // initialize with 1 
        Arrays.fill(lis, 1); 

        for (int i = 1; i < n; i++) { 
            for (int j = 0; j < i; j++) { 
                if (arr[i] > arr[j] && lis[i] < lis[j] + 1) { 
                    lis[i] = lis[j] + 1; 
                } 
            } 
        } 

        // get the max of all lis[] values 
        int max = 0; 
        for (int i = 0; i < n; i++) { 
            if (max < lis[i]) { 
                max = lis[i]; 
            } 
        } 

        return max; 
    } 

    public static void main(String[] args) 
    { 
        int arr[] = { 1, 5, 3, 4, 8, 6, 7 }; 
        int n = arr.length; 
        System.out.println("The length of LIS is " + findLIS(arr)); 
    } 
}

