public class VerifySameLinkedLists { 

    // Node class to create Node of LinkedList  
    static class Node { 
        int data; 
        Node next; 
    }; 

    // Utility function to create a new Node 
    static Node newNode(int key) 
    { 
        Node temp = new Node(); 
        temp.data = key; 
        temp.next = null; 
        return temp; 
    } 

    /* This function returns true if both linked lists have the same data 
    and with same structure*/
    static boolean compareUtil( Node n1, Node n2) 
    { 
        // Both nodes are NULL 
        if (n1 == null && n2 == null) 
            return true; 

        // Only one of the nodes is NULL 
        if (n1 == null || n2 == null) 
            return false; 

        if (n1.data == n2.data) 
            return compareUtil(n1.next, n2.next); 

        return false; 
    } 

    // This function for comparing two linked lists. 
    static boolean compare(Node n1, Node n2) 
    { 
        // Both nodes are NULL 
        if (n1 == null && n2 == null) 
            return true; 

        // One of the nodes is NULL 
        if (n1 == null || n2 == null) 
            return false; 

        return compareUtil(n1, n2); 
    } 

    // Driver program to test above 
    public static void main(String args[]) 
    { 
        Node head1 = newNode(1); 
        head1.next = newNode(2); 
        head1.next.next = newNode(3); 
        head1.next.next.next = newNode(4); 
        head1.next.next.next.next = newNode(5); 

        Node head2 = newNode(1); 
        head2.next = newNode(2); 
        head2.next.next = newNode(3); 
        head2.next.next.next = newNode(4); 
        head2.next.next.next.next = newNode(5); 

        if (compare(head1, head2)) 
            System.out.println("Both Linked Lists have same "
                              + "elements"); 
        else
            System.out.println("Linked Lists do not have same "
                              + "elements"); 
    } 
}

