#include <algorithm>
#include <string>

// Computes the Levenshtein distance between two strings
int levenshtein(std::string a, std::string b) {
 int m = a.length(), n = b.length();
 if (m == 0) return n;
 if (n == 0) return m;

 int d[m + 1][n + 1];
 for (int i = 0; i <= m; i++)
 d[i][0] = i;
 for (int i = 0; i <= n; i++)
 d[0][i] = i;
 for (int i = 1; i <= m; i++) {
 for (int j = 1; j <= n; j++) {
 int substitution = (a[i - 1] == b[j - 1]) ? 0 : 1;
 d[i][j] = std::min({d[i - 1][j] + 1, d[i][j - 1] + 1, d[i - 1][j - 1] + substitution});
 }
 }
 return d[m][n];
