def longestCommonSubstring(s1, s2):
    n = len(s1)
    m = len(s2)
    longest = ""

    # Create a 2D array to store 
    table = [[0]*(m+1) for _ in range(n+1)]

    # Iterate over s1
    for i in range(n):
        # Iterate over s2
        for j in range(m):
            if s1[i] == s2[j]:
                table[i+1][j+1] = table[i][j] + 1 
                if table[i+1][j+1] > len(longest):
                    longest = s1[i-table[i+1][j+1]+1:i+1]
    return longest

