def binary_search(arr, x):
    '''This function takes a sorted array and a target value and returns the index of the target value if found, -1 otherwise.'''
    low = 0
    high = len(arr) - 1
    while low <= high:
        mid = (low + high) // 2
        if arr[mid] == x:
            return mid
        elif arr[mid] > x:
            high = mid - 1
        else:
            low = mid + 1
    return -1

def sort_out_of_order_list(lst):
    index = -1
    for i in range(len(lst)-1):
        if lst[i] > lst[i+1]:
            index = i 
            break
    sorted_lst = lst[:index] + sorted(lst[index:])
    return sorted_lst

