        let minimum = i;
        for (let j = i+1; j < arr.length; j++) {
            if (arr[minimum] > arr[j]) {
                minimum = j;
            }
        }
        let temp = arr[i];
        arr[i] = arr[minimum];
        arr[minimum] = temp;
    }
    return arr;
