                dp[i][j] = 0
            elif s1[i-1] == s2[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
                if dp[i][j] > maxLength:
                    res = s1[i-dp[i][j]:i]
                    maxLength = len(res)
