public LinkedListNode sortList(LinkedListNode head) {
    // base cases
    if (head == null || head.next == null) {
        return head;
    }

    // get the middle of the list
    ListNode slowPtr = head;
    ListNode fastPtr = head;
    while (fastPtr.next != null && fastPtr.next.next != null) {
        slowPtr = slowPtr.next;
        fastPtr = fastPtr.next.next;
    }

    // split the list in two halves
    ListNode head1 = head;
    ListNode head2 = slowPtr.next;
    slowPtr.next = null;

    // now recursively sort the two halves
    head1 = sortList(head1);
    head2 = sortList(head2);

    // Merge the two sorted lists
    return mergeSort(head1, head2);
}

public LinkedListNode mergeSort(LinkedListNode headA, LinkedListNode headB) {
    // Base cases
    if (headA == null) {
        return headB;
    }
    if (headB == null) {
       return headA;
    }

    // stack pointers
    LinkedListNode currA = headA;
    LinkedListNode currB = headB;
    LinkedListNode resultHead = new LinkedListNode("");
    LinkedListNode currResult = resultHead;

    // the loop
    while (currA != null && currB != null) {
        if (currA.value < currB.value) {
            currResult.next = currA;
            currA = currA.next;
        }
        else {
            currResult.next = currB;
            currB = currB.next;
        }
        currResult = currResult.next;
    }

    // attach what's remaining
    currResult.next = (currA == null) ? currB : currA;

    return resultHead.next;
}

