def binary_search(arr, target):
    left = 0 
    right = len(arr) - 1

    while left <= right:
        mid = (left + right) // 2

        if target == arr[mid]:
            return True

        elif target < arr[mid]:
            right = mid - 1

        else: 
            left = mid + 1

    return False

