function longestCommonSubstring(str1, str2) {
  var longest = '';
  for (let i = 0; i < str1.length; i++) {
    for (let j = 0; j < str2.length; j++) {
      let lcs = '';
      let x = i;
      let y = j;
      while (str1[x] && str2[y] && str1[x] === str2[y]) {
        lcs += str1[x];
        x++;
        y++;
      }
      if (lcs.length > longest.length) {
        longest = lcs;
      }
    }
  }
  return longest;
}

