def caesar_cipher(s, key):
    cipher = ''
    for char in s: 
        if not char.isalpha():
            cipher += char
        elif char.isupper():
            cipher += chr((ord(char) + key - 65) % 26 + 65)
        else:
            cipher += chr((ord(char) + key - 97) % 26 + 97) 
