{ 
    int max_sum = 0; 

    // Finding max sum subarray of size k 
    for (int i=0; i<arr.length-k+1; i++) 
    { 
        int current_sum = 0; 

        // Calculating the current sum 
        for (int j=0; j<k; j++) 
            current_sum = current_sum + arr[i+j]; 

        // Updating maximum sum, if needed 
        max_sum = Math.max(max_sum, current_sum); 
