function findLongestConsecutiveDates(dates) {
  let longestConsecutive = 0;
  let currConsecutive = 0;

  for (let i = 0; i < dates.length; i++) {
    const currDate = new Date(dates[i]);
    const nextDate = new Date(dates[i + 1]);

    if (currDate.setDate(currDate.getDate() + 1) === nextDate.getTime()) {
      currConsecutive++;
    } else {
      longestConsecutive = Math.max(currConsecutive, longestConsecutive);
      currConsecutive = 0;
    }
  }

  return longestConsecutive + 1;
}

