class Node 
{ 
    int data; 
    Node next; 
    Node prev; 
}; 

public class LinkedList 
{ 
    Node head; //head of list 
    Node last; 

    // This function should insert a new node at the end 
    public void addToTheLast(Node node) 
    {
         if (head == null) 
        { 
            head = node; 
            last = node; 
            head.next = node;
            node.prev = head;
        } 
        else
        { 
            Node temp = head; 
            node.prev = temp; 
            while (temp.next != null) 
                temp = temp.next;

            temp.next = node; 
            node.prev=temp;
            last = node;
        }
    } 

    public void printList(Node node) 
    { 
        Node temp = node;
        System.out.println("Forward Traversal in Doubly Linked List is :"); 
        while (node != null) 
        { 
            System.out.print(node.data + "<->"); 
            last = node; 
            node = node.next; 
        } 
        System.out.print("null\n"); 
        System.out.println("Backward Traversal in Doubly Linked list is :");
        while (last != null) 
        { 
            System.out.print(last.data + "<->"); 
            last = last.prev; 
        } 
        System.out.print("null"); 
    } 

    /* Driver program to test above functions*/
    public static void main(String[] args) 
    { 
        /* Start with the empty list */
        LinkedList dll = new LinkedList(); 

        // Insert 6.  So linked list becomes 6->NULL
        dll.addToTheLast(new Node(1)); 
        dll.addToTheLast(new Node(4)); 
        dll.addToTheLast(new Node(7));
        dll.addToTheLast(new Node(9));

        dll.printList(dll.head); 
    } 
} 

Output: Forward Traversal in Doubly Linked List is :
1<->4<->7<->9->null 
Backward Traversal in Doubly Linked list is :
9<->7<->4<->1->null

