def longest_common_prefix(strs):
    if not strs:
        return ""

    prefix = strs[0]
    l = len(prefix)
    for i in range(1, len(strs)):
        while strs[i][:l] != prefix:
            l -= 1
            prefix = prefix[:l]
        if l == 0:
            return ""

    return prefix

