# Function to convert Infix expression to postfix  
def infixToPostfix(exp): 

    # Create empty stack 
    s = [] 

    # Output string 
    out = "" 

    # Loop through expressions 
    for i in exp: 

        # If i is an operand 
        if i.isalpha(): 
            out += i 

        # If character is (, push it to stack 
        elif i == '(': 
            s.append(i) 

        # If character is ), 
        # pop from stack till ( is encountered 
        elif i == ')': 
            while(len(s) != 0 and s[-1] != '('): 
                a = s.pop() 
                out += a 
            if (len(s) != 0 and s[-1] != '('): 
                return -1
            else: 
                s.pop() 

        # If character is an operator 
        else: 
            while(len(s) != 0 and precedence(i) <= precedence(s[-1])): 
                out += s.pop() 
            s.append(i)  

    # Pop all characters from stack 
    while len(s) != 0: 
        out += s.pop() 

    return out

