  const hours = parseInt(time.substr(0, 2)); 
  const minutes = time.substr(3); 

  let timeOfDay; 
  let time12Hour; 

  if (hours === 0) { 
    timeOfDay = "AM";
    time12Hour = "12" + minutes;
  }else if (hours < 12) { 
    timeOfDay = "AM"; 
    time12Hour = time; 
  }else if (hours === 12){ 
    timeOfDay = "PM"; 
    time12Hour = time; 
  }else { 
    timeOfDay = "PM"; 
    time12Hour = (hours - 12).toString() + minutes; 
  } 

  return time12Hour + " " + timeOfDay 
}

