function convertTemp(temp, inputUnit, outputUnit) {
    if (inputUnit === 'C') {
        if (outputUnit === 'F') {
            return temp * (9/5) + 32;
        } else if (outputUnit === 'K') {
            return temp + 273.15;
        } else {
            return temp;
        }
    } else if (inputUnit === 'F') {
        if (outputUnit === 'C') {
            return (temp - 32) * (5/9);
        } else if (outputUnit === 'K') {
            return (temp + 459.67) * (5/9);
        } else {
            return temp;
        }
    } else if (inputUnit === 'K') {
        if (outputUnit === 'C') {
            return temp - 273.15;
        } else if (outputUnit === 'F') {
            return temp * (9/5) - 459.67;
        } else {
            return temp;
        }
    }
}

