    public static void selectionSort(int[] array) 
    { 
        int n = array.length; 

        for (int i = 0; i < n-1; i++) 
        { 
            int min_idx = i; 
            for (int j = i+1; j < n; j++) 
                if (array[j] < array[min_idx]) 
                    min_idx = j; 

            int temp = array[min_idx]; 
            array[min_idx] = array[i]; 
            array[i] = temp; 
        } 
    } 

    public static void main(String[] args) 
    { 
        int[] list = {4, 9, 1, 8, 3};
        selectionSort(list);
        for (int i = 0; i < list.length;  i++) 
            System.out.print(list[i] + " ");
    } 
}

