def sort_array(A):
    for i in range(len(A) - 1):
        min = A[i]
        min_index = i
        for j in range(i + 1, len(A)):
            if A[j] < min:
                min = A[j]
                min_index = j
        if min_index != i:
            A[i], A[min_index] = A[min_index], A[i]
    return A

