// A utility function to create a new node 
struct Node* newNode(int data) 
{ 
    struct Node* node = (struct Node*)malloc(sizeof(struct Node)); 
    node->data = data; 
    node->left = node->right = NULL; 
    return node; 
}; 

// Function to find if given binary tree is BST or not
bool isBST(Node* root) {
    if (root == NULL)
        return true;

    // Left subtree is a BST and its value should be 
    // less than root node's data 
    if (!isBST(root->left) || 
        (root->left != NULL && 
        root->left->data > root->data)) 
        return false; 

    // Right subtree is a BST and its value should 
    // be greater than root node's data 
    if (!isBST(root->right) || 
        (root->right != NULL && 
        root->right->data < root->data)) 
        return false; 

    // All conditions are satisfied 
    return true; 
} 


