            if ( var_h == 6 ) var_h = 0;  // H must be < 1
            int var_i = (int) var_h;  // Or ... var_i = floor( var_h )
            float var_1 = v * ( 1 - s );
            float var_2 = v * ( 1 - s * ( var_h - var_i ) );
            float var_3 = v * ( 1 - s * ( 1 - ( var_h - var_i ) ) );

            if ( var_i == 0 ) { 
                r = v     ;
                g = var_3 ;
                b = var_1 ;
            } else if ( var_i == 1 ) { 
                r = var_2 ;
                g = v     ;
                b = var_1 ;
            } else if ( var_i == 2 ) { 
                r = var_1 ;
                g = v     ;
                b = var_3 ;
            } else if ( var_i == 3 ) { 
                r = var_1 ;
                g = var_2 ;
                b = v     ;
            } else if ( var_i == 4 ) { 
                r = var_3 ;
                g = var_1 ;
                b = v     ;
            } else { 
                r = v     ;
                g = var_1 ;
                b = var_2 ;
            }
        }
        int[] rgb = new int[3];
        rgb[0] = (int)(r * 255);
        rgb[1] = (int)(g * 255);
        rgb[2] = (int)(b * 255);
        return rgb;
    }

