#define BLOCK_WIDTH 256
#define GRID_WIDTH 64

// This is the kernel (or codes) that will be executed for each thread:
__global__ void sum_matrices(int *A, int *B, int *C){
	// Get the thread's x and y positions 
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    int y = blockIdx.y * blockDim.y + threadIdx.y;

    // Compute the relative indices as each thread processes one element
    int indexA = y * BLOCK_WIDTH + x;
    int indexB = y * BLOCK_WIDTH + x;
    int indexC = y * BLOCK_WIDTH + x;

    // Perform the actual computation
    C[indexC] = A[indexA] + B[indexB];
}

// Host code:
int main(void) { 
    // Allocate and initialize the device memory
    int *A = (int*)malloc(BLOCK_WIDTH*GRID_WIDTH * sizeof(int));
    int *B = (int*)malloc(BLOCK_WIDTH*GRID_WIDTH * sizeof(int));
    int *C = (int*)malloc(BLOCK_WIDTH*GRID_WIDTH * sizeof(int));

    // Input Arrays 
    int arr1[2][2] = {{2, 4}, {7, 8}}; 
    int arr2[2][2] = {{5, 1}, {6, 4}}; 

    // Copy the input data 
    memcpy(A, arr1, BLOCK_WIDTH*GRID_WIDTH * sizeof(int)); 
    memcpy(B, arr2, BLOCK_WIDTH*GRID_WIDTH * sizeof(int)); 

    // Launch the kernel 
    sum_matrices<<<GRID_WIDTH, BLOCK_WIDTH>>>(A, B, C);

    // Copy the result back to the host 
    memcpy(arr3, C, BLOCK_WIDTH*GRID_WIDTH * sizeof(int)); 

    // Print the result 
    printf("\nSum of A + B = \n"); 
    for (int i = 0; i < 2; i++) { 
        for (int j = 0; j < 2; j++) {
            printf("%d\t", arr3[i][j]); 
        } 
        printf("\n"); 
    } 

    // Free the memory
    free(A);
    free(B);
    free(C);
    return 0; 
}

