 private RecyclerView recyclerView;
 private List<Expense> expenses;
 private ExpenseAdapter expenseAdapter;

 @Override
 protected void onCreate(Bundle savedInstanceState) {
 super.onCreate(savedInstanceState);
 setContentView(R.layout.activity_main);

 // Load the existing expenses from the room database
 expenses = ExpenseDatabase.getInstance(this).getExpenseDao().getExpenses();

 // Create the recyclerview adapter and set it
 expenseAdapter = new ExpenseAdapter(this, expenses);
 recyclerView = (RecyclerView) findViewById(R.id.recyclerview);
 recyclerView.setAdapter(expenseAdapter);

 // Setup the intents and listeners
 setupNewExpenseIntent();
 setupEditExpenseIntent();
 setupDeleteExpenseIntent();
 setupNewExpenseListener();
 }

 // Method to launch the intent to add a new expense
 private void setupNewExpenseIntent() {
 FloatingActionButton addFAB = findViewById(R.id.add_fab);

 addFAB.setOnClickListener(view -> {
 Intent intent = new Intent(this, AddExpenseActivity.class);
 startActivity(intent);
 });
 }

 // Method to launch the intent to edit an existing expense
 private void setupEditExpenseIntent() {
 expenseAdapter.setOnItemEditListener((position, expenseId) -> {
 Intent intent = new Intent(this, AddExpenseActivity.class);
 intent.putExtra(AddExpenseActivity.EXTRA_EXPENSE_ID, expenseId);
 startActivity(intent);
 });
 }

 // Method to launch the intent to delete an existing expense
 private void setupDeleteExpenseIntent() {
 expenseAdapter.setOnItemDeleteListener((position, expenseId) -> {
 deleteExpense(expenseId);
 });
 }

 private void setupNewExpenseListener() {
 // Listen for new expenses
 ExpenseDatabase.getInstance(this).getExpenseDao().getExpensesLiveData().observe(this, expenses -> {
 expenseAdapter.updateData(expenses);
 });
 }

 private void deleteExpense(long expenseId) {
 // Delete the expense
 ExpenseDatabase.getInstance(this).getExpenseDao().delete(expenseId);
 expenseAdapter.notifyDataSetChanged();
 }

}

