public static void enumeratePermutations(int[] arr) {
    enumeratePermutationsHelper(arr, 0);
}

private static void enumeratePermutationsHelper(int[] arr, int index) {
    if (index == arr.length - 1) {
        for (int num : arr) {
            System.out.print(num + " ");
        }
        System.out.println();
    } else {
        for (int i = index; i < arr.length; i++) {
            int temp = arr[index];
            arr[index] = arr[i];
            arr[i] = temp;
            enumeratePermutationsHelper(arr, index + 1);
            temp = arr[index];
            arr[index] = arr[i];
            arr[i] = temp;
        }
    }
}

