const MOVE_STEP = 0.1;
const SVG_SIZE = 500;
const SVG_CENTER = SVG_SIZE / 2;
const GRAVITY_MAGNITUDE = 9.81;

function animateSVG(svg, velocityMagnitude, velocityAngle, dragCoefficient) {
  const totalIterations = (SVG_SIZE / velocityMagnitude) / MOVE_STEP;
  const velocityX = velocityMagnitude * Math.cos((velocityAngle * Math.PI) / 180);
  const velocityY = velocityMagnitude * Math.sin((velocityAngle * Math.PI) / 180);

  let coordinates = [SVG_CENTER, SVG_CENTER];
  let velocity = [velocityX, velocityY];

  for (let i = 0; i < totalIterations; i++) {
    svg.circle(coordinates[0], coordinates[1], 5).fill('red');

    const dragForceX = -dragCoefficient * velocity[0];
    const dragForceY = -dragCoefficient * velocity[1];

    velocity[0] = velocity[0] + dragForceX * MOVE_STEP + (GRAVITY_MAGNITUDE * MOVE_STEP);
    velocity[1] = velocity[1] + dragForceY * MOVE_STEP + (GRAVITY_MAGNITUDE * MOVE_STEP);

    coordinates[0] = coordinates[0] + velocity[0] * MOVE_STEP;
    coordinates[1] = coordinates[1] + velocity[1] * MOVE_STEP;
  }
}

