import math

def find_closest_pair(points):
    min_dist = math.inf
    closest_pair = []
    for i in range(len(points)-1):
        for j in range(i+1, len(points)):
            dist = ((points[i][0]-points[j][0])**2 + (points[i][1]-points[j][1])**2)**0.5
            if dist < min_dist:
                min_dist = dist
                closest_pair = [(i, j)]
            elif dist == min_dist:
                closest_pair.append((i, j))
    return closest_pair

