const request = require('request');

const getWikiArticleParagraph = (query: string): Promise<string> => {
 const url = `https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch=${query}&format=json`;
 return new Promise<string>((resolve, reject) => {
 request(url, (error, response, body) => {
 if (!error && response.statusCode === 200) {
 const data = JSON.parse(body);
 const pageid = data.query.search[0].pageid;
 const url2 = `https://en.wikipedia.org/w/api.php?action=query&prop=extracts&pageids=${pageid}&format=json`;
 request(url2, (error2, response2, body2) => {
 if (!error2 && response2.statusCode === 200) {
 const data2 = JSON.parse(body2);
 const title = data2.query?.pages[pageid]?.title ?? '';
 const extract = data2.query?.pages[pageid]?.extract ?? '';
 resolve(`${title}\n\n${extract}`);
 } else {
 reject(error2);
 }
 });
 } else {
 reject(error);
 }
 });
 });
};

