const HomeScreen = () => {
 const [data, setData] = useState([5, 10, 15, 20, 25]);

 // Add a new data point to the chart
 const addPoint = () => {
  let newData = [...data];
  newData.push(newData[newData.length - 1] + 5);
  setData(newData);
 };

 return (
  <View style={styles.container}>
   <Text style={styles.subhead}>Daily Mileage</Text>

   <LineChart
     style={styles.chart}
    data={data}
    svg={{ stroke: 'rgb(134, 65, 244)' }}
   />
   <Grid />

   <TouchableOpacity onPress={addPoint} style={styles.button}>
    <Text style={styles.buttonText}>Add 1 mile</Text>
   </TouchableOpacity>
  </View>
 );
};

const styles = StyleSheet.create({
 container: {
  flex: 1,
  backgroundColor: '#f5f5f5',
  alignItems: 'center',
 },
 subhead: {
  fontSize: 24,
  margin: 20,
  fontWeight: '600',
 },
 chart: {
  marginTop: 20,
  width: '90%',
  height: 250,
 },
 button: {
  backgroundColor: '#008000',
  justifyContent: 'center',
  alignItems: 'center',
  padding: 15,
  margin: 20,
  width: 200,
  borderRadius: 7,
 },
 buttonText: {
  color: '#ffffff',
  fontSize: 16,
  fontWeight: '600',
  textTransform: 'uppercase',
 },
});
export default HomeScreen;

