public class CoinChange {
 public static int minCoins(int amount, int[] denominations) {
  int numCoins = 0;
  int i = denominations.length - 1;

  while (amount > 0) {
   while (denominations[i] > amount) {
    i--;
   }
   numCoins++;
   amount -= denominations[i];
  }

  return numCoins;
 }
}

