public class calcSumOfTwoLargeNumbers 
{
    public static void main(String[] args) 
    {
        String num1 = "17456";  
        String num2 = "56877"; 

        // call to the function which calculates the sum   
        String sum = findSum(num1, num2); 

        //prints the result 
        System.out.println("Sum is: "+sum);
    } 

    static String findSum(String str1, String str2) 
    {  
        // will contain the result 
        String result = "";  

        // to store the lengths of two strings 
        int len1 = str1.length(), len2 = str2.length();  

        // to make both strings of equal lengths  
        if (len1 < len2) 
        { 
            for (int i = 0; i < len2 - len1; i++) 
            {
                str1 = '0' + str1;  
            }  
        } 
        else if (len1 > len2) 
        {  
            for (int i = 0; i < len1 - len2; i++) 
            {  
                str2 = '0' + str2;  
            }  
        }  

        // declare and initialize carry  
        int carry = 0;  

        // calculating sum from last characters to first  
        for (int i = str1.length() - 1; i >= 0; i--) 
        {  
            // take the summation of last characters of both strings  
            int sum = ((int)(str1.charAt(i) - '0') + 
                       (int)(str2.charAt(i) - '0') + 
                       carry);  

            // update result and carry , prepend the sum to result  
            result = (char)(sum % 10 + '0') + result;  
            carry = sum / 10;  
        }  

        // if carry != 0 append the carry to result  
        if (carry != 0) 
            result = (char)(carry + '0') + result;  

        return result;  
    } 
}

