                str2 = '0' + str2;  
            }  
        }  

        // declare and initialize carry  
        int carry = 0;  

        // calculating sum from last characters to first  
        for (int i = str1.length() - 1; i >= 0; i--) 
        {  
            // take the summation of last characters of both strings  
            int sum = ((int)(str1.charAt(i) - '0') + 
                       (int)(str2.charAt(i) - '0') + 
                       carry);  

            // update result and carry , prepend the sum to result  
            result = (char)(sum % 10 + '0') + result;  
            carry = sum / 10;  
        }  

        // if carry != 0 append the carry to result  
        if (carry != 0) 
            result = (char)(carry + '0') + result;  

        return result;  
    } 
}

