public class LowestCommonAncestor {
    public static int lca(TreeNode root, int x, int y) {
        if (root == null) {
            return -1;
        } else if (root.data == x || root.data == y) {
            return root.data;
        }
        int left_lca = lca(root.left, x, y);
        int right_lca = lca(root.right, x, y);
        if (left_lca != -1 && right_lca != -1) {
            return root.data;
        }
        return (left_lca != -1) ? left_lca : right_lca;
    }

    public static void main(String[] args) {
        TreeNode root = new TreeNode(5);
        root.left = new TreeNode(2);
        root.right = new TreeNode(8);
        root.left.left = new TreeNode(1);
        root.left.right = new TreeNode(4);
        root.right.left = new TreeNode(6); 
        root.right.right = new TreeNode(9);
        int lca = lca(root, 4, 6); 
        System.out.println("Lowest Common Ancestor of 4 and 6 is: " + lca); 
    }
}

