fun encodeMessage(msg:String):String {
 val encodedMsg = StringBuilder()
 for (c in msg) {
  when {
   c.isUpperCase() -> encodedMsg.append('A' - c.toInt())
   c.isLowerCase() -> encodedMsg.append('a' - c.toInt())
   else -> encodedMsg.append(c)
  }
 }
