}

fun decodeMessage(msg:String):String {
 val decodedMsg = StringBuilder()
 for (c in msg) {
  when {
   c.toInt() < 0 -> decodedMsg.append(-c + 'A'.toInt())
   c.toInt() < 26 -> decodedMsg.append(-c + 'a'.toInt())
   else -> decodedMsg.append(c)
  }
 }
 return decodedMsg.toString()
}

