def max_sum_subarray(arr, k):
    if (len(arr)) < k:
        return 0

    max_sum = 0
    for i in range(len(arr) - k + 1):
        current_sum = 0
        for j in range(k):
            current_sum += arr[i+j]
        max_sum = max(max_sum, current_sum)
    return max_sum

