def longest_increasing_subsequence(sequence):
    n = len(sequence) 
    lis = [1]*n

    for i in range (1 , n): 
        for j in range(0 , i): 
            if sequence[i] > sequence[j] and lis[i] < lis[j] + 1 : 
                lis[i] = lis[j]+1
    return max(lis)

