"""
A PriorityQueue class to maintain tasks based on their priority.

This PriorityQueue class implements a max-heap to maintain the ordering of tasks by their priority.

The priority queue supports the following operations:

- insert(priority, data): Inserts a new task with the given priority and data, and updates the max-heap structure accordingly.

- pop(): Removes and returns the task with the highest priority in the queue.

-change_priority(new_priority, data): Changes the priority of the task with matching data to the given new_priority.
"""

class PriorityQueueNode:
	def __init__(self, priority, data):
		self.priority = priority
		self.data = data

	def __lt__(self, other):
		return self.priority < other.priority

class PriorityQueue:
	def __init__(self):
		self.heap = []

	def __len__(self):
		return len(self.heap)

	def insert(self, priority, data):
		node = PriorityQueueNode(priority, data)
		self.heap.append(node)
		self._heapify_up(len(self.heap) - 1)

	def pop(self):
		if len(self.heap) == 0:
			return None

		root = self.heap[0]
		last_node = self.heap.pop()

		if len(self.heap) > 0:
			self.heap[0] = last_node
			self._heapify_down(0)

		return root

	def change_priority(self, priority, data):
		for i, node in enumerate(self.heap):
			if node.data == data:
				self.heap[i].priority = priority
				self._heapify_up(i)
				self._heapify_down(i)
				break

	def _heapify_up(self, index):
		if index == 0:
			return

		parent_index = (index - 1) // 2

		if self.heap[parent_index] < self.heap[index]:
			self.heap[parent_index], self.heap[index] = self.heap[index], self.heap[parent_index]
			self._heapify_up(parent_index)

	def _heapify_down(self, index):
		left_index = 2 * index + 1
		right_index = 2 * index + 2
		largest_index = index

		if left_index < len(self.heap) and self.heap[left_index] > self.heap[largest_index]:
			largest_index = left_index

		if right_index < len(self.heap) and self.heap[right_index] > self.heap[largest_index]:
			largest_index = right_index

		if largest_index != index:
			self.heap[largest_index], self.heap[index] = self.heap[index], self.heap[largest_index]
			self._heapify_down(largest_index)

