public double calculateMedian(int[] nums) {
  if (nums.length == 0) {
    throw new IllegalArgumentException("Input array is empty!");
  }

  Arrays.sort(nums);
  if (nums.length % 2 == 0) {
    return (nums[nums.length / 2] + nums[nums.length / 2 - 1]) / 2.0;
  } else {
    return nums[nums.length / 2];
  }
}

