class PriorityQueue {
  private int maxSize;
  private int size;
  private int[] array;

  public PriorityQueue(int maxSize) {
    this.maxSize = maxSize;
    this.array = new int[this.maxSize];
    this.size = 0;
  }

  // Adds a new element to the priority queue
  public void addElement(int element) {
    if (this.size == this.maxSize) {
      // Priority queue is full, throw a exception
      throw new IllegalStateException("Queue is full");
    }
    int i = this.size - 1;
    while (i >= 0 && this.array[i] < element) {
      this.array[i + 1] = this.array[i];
      i--;
    }
    this.array[i + 1] = element;
    this.size++;
  }

  // Removes and returns the highest priority element from the priority queue
  public int deleteMax() {
    if (this.size == 0) {
      // Priority queue is empty, throw a exception
